INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'sl', 42, 1, NULL, 'Martin Bucer em Sl 42:1', 'Martin Bucer destaca a centralidade das Escrituras e da graça soberana. Em Salmos 42, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Martin Bucer', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'sl', 43, 1, NULL, 'Charles Finney em Sl 43:1', 'Charles Finney interpreta este versículo a partir de o chamado ao arrependimento, fé viva e missão. Em Salmos 43, Deus revela adoração, sabedoria e temor do Senhor de forma pastoral e transformadora, promovendo fidelidade na aliança. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Charles Finney', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'sl', 44, 1, NULL, 'Jamieson-Fausset-Brown em Sl 44:1', 'Jamieson-Fausset-Brown destaca a exposição textual com aplicação pastoral objetiva. Em Salmos 44, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para vida de oração. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Jamieson-Fausset-Brown', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'sl', 45, 1, NULL, 'John Knox em Sl 45:1', 'Na leitura de John Knox, vemos a centralidade das Escrituras e da graça soberana. Salmos 45 evidencia adoração, sabedoria e temor do Senhor como eixo da vida do povo de Deus, com ênfase em esperança escatológica. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'John Knox', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'sl', 46, 1, NULL, 'George Whitefield em Sl 46:1', 'Segundo George Whitefield, o chamado ao arrependimento, fé viva e missão ilumina o sentido deste texto. Salmos 46 mostra que adoração, sabedoria e temor do Senhor sustenta a caminhada da fé, especialmente em obediência da fé. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'George Whitefield', 'commentary', '#0E7490', NOW()),
